257	/// The cockpit session name for a project: `panopt-<basename>-<hash>`. The
258	/// basename is reduced to characters Zellij accepts; the hash is a short
259	/// fingerprint of the canonical project path, so two projects sharing a
260	/// basename (`~/a/frontend`, `~/b/frontend`) land on distinct sessions
261	/// instead of one silently attaching to the other's cockpit.
262	fn session_name(project: &Path) -> String {
263	    let base = project
264	        .file_name()
265	        .and_then(|n| n.to_str())
266	        .unwrap_or("project");
267	    let safe: String = base
268	        .chars()
269	        .map(|c| if c.is_ascii_alphanumeric() { c } else { '-' })
270	        .collect();
271	    let hash = short_path_hash(project);
272	    format!("panopt-{safe}-{hash}")
273	}
