275	/// Stable 7-hex-char fingerprint of the canonical project path. Used as the
276	/// disambiguating suffix on the cockpit session name; see [`session_name`].
277	fn short_path_hash(project: &Path) -> String {
278	    use std::hash::{Hash, Hasher};
279	    let mut hasher = std::collections::hash_map::DefaultHasher::new();
280	    project.hash(&mut hasher);
281	    let h = hasher.finish();
282	    format!("{h:016x}").chars().take(7).collect()
283	}
