285	/// Whether a Zellij session named `name` exists, and if so whether it is live
286	/// or dead (exited but still resurrectable).
287	enum SessionState {
288	    Absent,
289	    Live,
290	    Dead,
291	}
292	
293	fn session_state(name: &str) -> SessionState {
294	    let Ok(out) = Command::new("zellij").arg("list-sessions").output() else {
295	        return SessionState::Absent;
296	    };
297	    let text = strip_ansi(&String::from_utf8_lossy(&out.stdout));
298	    for line in text.lines() {
299	        if line.split_whitespace().next() == Some(name) {
300	            return if line.contains("EXITED") {
301	                SessionState::Dead
302	            } else {
303	                SessionState::Live
304	            };
305	        }
306	    }
307	    SessionState::Absent
308	}
