310	/// Drop ANSI escape sequences so `zellij list-sessions` output can be parsed.
311	fn strip_ansi(s: &str) -> String {
312	    let mut out = String::with_capacity(s.len());
313	    let mut chars = s.chars();
314	    while let Some(c) = chars.next() {
315	        if c == '\u{1b}' {
316	            // Skip a CSI sequence up to and including its final letter.
317	            for n in chars.by_ref() {
318	                if n.is_ascii_alphabetic() {
319	                    break;
320	                }
321	            }
322	        } else {
323	            out.push(c);
324	        }
325	    }
326	    out
327	}
